// Etsy Ledger-Entry → etsy_transactions-Schema
// Doku: https://developers.etsy.com/documentation/reference#operation/getShopPaymentAccountLedgerEntries

const ENTRY_TYPE_MAP = {
  'SALE':              'sale',
  'TRANSACTION':       'sale',
  'FEE':               'fee_transaction',
  'LISTING_FEE':       'fee_listing',
  'ADS_FEE':           'fee_ads',
  'PROCESSING_FEE':    'fee_processing',
  'REFUND':            'refund',
  'TAX':               'tax',
  'PAYOUT':            'payout',
};

const results = $input.item.json.results ?? [];

return results.map(entry => {
  // Etsy gibt Beträge in Cents zurück (divisor = 100)
  const toEur = (v, divisor = 100) => v != null ? (v / divisor) : null;

  // Typ normalisieren (Fallback: fee_transaction)
  const rawType = (entry.ledger_entry_type ?? '').toUpperCase();
  const type    = ENTRY_TYPE_MAP[rawType] ?? 'fee_transaction';

  const date    = new Date(entry.create_date * 1000).toISOString();
  const month   = date.slice(0, 7); // '2026-04'

  // Betrag: Etsy gibt positive/negative Werte in Cents
  const amount    = toEur(entry.amount);
  const feeAmount = toEur(entry.fee_gross);
  const netAmount = amount != null && feeAmount != null
    ? amount - Math.abs(feeAmount)
    : amount;

  return {
    json: {
      transaction_id: String(entry.entry_id),
      order_id:       entry.reference_id ? String(entry.reference_id) : null,
      type,
      description:    entry.type ?? null,
      amount,
      fee_amount:     feeAmount,
      net_amount:     netAmount,
      currency:       entry.currency ?? 'EUR',
      date,
      month,
    }
  };
});
